-- Helper: check if a URI starts with a given prefix
local function uri_starts_with(uri, prefix)
    return string.sub(uri, 1, #prefix) == prefix
end

-- Helper: check if the endpoint should skip permission checks
local function should_skip_permission_check(uri)
    for _, endpoint in ipairs(skip_endpoints) do
        if uri_starts_with(uri, endpoint) then
            return true
        end
    end
    return false
end

-- Helper: decode a base64url string
local function base64url_decode(input)
    local remainder = #input % 4
    if remainder > 0 then
        input = input .. string.rep("=", 4 - remainder)
    end
    input = input:gsub("-", "+"):gsub("_", "/")
    return ngx.decode_base64(input)
end

-- Validate the authentication token (simple JWT-like validation)
local function validate_token(token)
    if not token or token == "" then
        return nil, "Missing authentication token"
    end

    -- Split token into parts (header.payload.signature)
    local parts = {}
    for part in string.gmatch(token, "[^%.]+") do
        table.insert(parts, part)
    end

    if #parts ~= 3 then
        return nil, "Invalid token format"
    end

    local header_b64 = parts[1]
    local payload_b64 = parts[2]
    local signature = parts[3]

    -- Verify signature using HMAC-SHA256
    local signing_input = header_b64 .. "." .. payload_b64
    local expected_signature = ngx.encode_base64(ngx.hmac_sha1(AUTH_SECRET, signing_input))
    -- Normalize to base64url
    expected_signature = expected_signature:gsub("+", "-"):gsub("/", "_"):gsub("=", "")

    if signature ~= expected_signature then
        return nil, "Invalid token signature"
    end

    -- Decode payload
    local payload_json = base64url_decode(payload_b64)
    if not payload_json then
        return nil, "Failed to decode token payload"
    end

    local payload, err = cjson.decode(payload_json)
    if not payload then
        return nil, "Failed to parse token payload: " .. (err or "unknown error")
    end

    -- Check token expiration
    local current_time = ngx.time()
    if payload.exp and payload.exp < current_time then
        return nil, "Token has expired"
    end

    -- Check issued at time (not from the future)
    if payload.iat and payload.iat > current_time + 60 then
        return nil, "Token issued in the future"
    end

    return payload, nil
end

-- Check if user role has permission for the requested URI
local function check_role_permission(role, uri)
    if not role or role == "" then
        return false, "No role specified"
    end

    local permissions = role_permissions[string.lower(role)]
    if not permissions then
        return false, "Unknown role: " .. role
    end

    for _, allowed_path in ipairs(permissions) do
        if uri_starts_with(uri, allowed_path) then
            return true, nil
        end
    end

    return false, "Insufficient permissions for role '" .. role .. "' to access " .. uri
end

-- Check if URI contains /admin or /api segments for special handling
local function is_protected_resource(uri)
    if string.match(uri, "/admin") or string.match(uri, "/api") then
        return true
    end
    return false
end

-- Main access control function
function _M.check_access()
    local uri = ngx.var.uri
