        -- Support "Bearer <token>" format
        token = string.match(auth_header, "^[Bb]earer%s+(.+)$")
        if not token then
            -- Also accept raw token in Authorization header
            token = auth_header
        end
    end

    -- Fallback: check for token in cookie
    if not token then
        token = ngx.var.cookie_auth_token
    end

    -- Fallback: check for token in query parameter (not recommended for production)
    if not token then
        local args = ngx.req.get_uri_args()
        token = args["token"]
    end

    if not token then
        ngx.log(ngx.WARN, "No authentication token provided for protected resource: ", uri)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.header["WWW-Authenticate"] = 'Bearer realm="access"'
        ngx.say(cjson.encode({
            error = "unauthorized",
            message = "Authentication token is required"
        }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Step 4: Validate the authentication token
    local payload, err = validate_token(token)
